VALUES
  ('social-worker-moex-02911', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '相較於社會工作督導，下列對於社會工作諮詢的敘述何者錯誤？', '["諮詢涉及的問題較督導為廣泛", "諮詢涉入組織的時間較長", "諮詢對於工作結果沒有行政上的權威或責任", "諮詢者與受諮詢者之間的關係通常是自願和同等地位的"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "f9469744500c", "answer_pdf_sha1": "07df2aebbe74", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02912', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '規劃（planning）是社會福利組織非常重要的工作項目，它是一種預設目標的過程，最終將設計出一個可 以達到目標的計畫。根據Weinbach（2003）的分類，以下何者屬於根據組織與環境的關係，強調根本性、 大方向、長期性規劃、未來導向的規劃類型？', '["權變性規劃（contingency planning）", "策略性規劃（strategic planning）", "作業性規劃（operational planning）", "長期性規劃（long-range planning）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "f9469744500c", "answer_pdf_sha1": "07df2aebbe74", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02913', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '社會工作實務最關心的理應是社工員的處遇對案主造成什麼改變（change）。從方案績效評估的角度來看， 若著重於案主的改變，在評估時應更注重方案的：', '["效率（efficiency）", "成效（effectiveness）", "經濟（economy）", "外部性（externality）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "f9469744500c", "answer_pdf_sha1": "07df2aebbe74", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02914', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '企業組織通常透過組織層級進行作業控制、財務控制、結構控制及策略控制，這些控制某種程度也適用 於社會服務組織，績效管理（performance management）即是控制過程的主軸，攸關社會服務目標的達成 至為重要。請問下列何者對「績效管理」的描述正確？', '["績效評估即是績效管理，評估績效即能達到績效管理的目標", "績效管理是一種迫使員工提升效率的手段，表格的填寫是必要的過程", "績效管理有利於提供發放績效獎金及秋後算帳的客觀依據", "績效管理是將組織的目標緊扣著組織的「人」（管理者和員工）與「事」（方案和組織）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "f9469744500c", "answer_pdf_sha1": "07df2aebbe74", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02915', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '下列何者符合管理學大師Peter F. Drucker（1955）所提出對於目標管理（management by objective, MBO）的 描述？', '["委託管理顧問公司之有效規劃和目標設定", "管理者和部屬設定與組織目標相關的個別目標", "在發展和選擇達成目標上必須有一致性的規範", "檢視最後階段成效與目標相關的績效"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "f9469744500c", "answer_pdf_sha1": "07df2aebbe74", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02916', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '預算具有控制、管理、規劃三大目的。在預算系統中以控制為主要目的是那一種預算系統？', '["單項預算系統（line-item budgeting）", "功能預算系統（functional budgeting）", "方案預算系統（program budgeting）", "績效預算系統（performance budgeting）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "f9469744500c", "answer_pdf_sha1": "07df2aebbe74", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02917', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '規劃服務方案時，在服務策略上特別採用外展服務的方法是為了想提升那一項服務品質？', '["保證性", "可靠性", "可近性", "安全性"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "f9469744500c", "answer_pdf_sha1": "07df2aebbe74", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02918', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '針對一個創新的方案，評估者關心的議題有：需求評定是否掌握服務對象的需求、方案所執行的措施是 否符合方案規劃的內容、方案的參與者是否為事先規劃的服務對象、方案經費是否運用得當等。根據這 些所關心的議題，此時評估者最需要做的評估是那一種？', '["過程評估", "總結性評估", "成本效益評估", "品質評估"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "f9469744500c", "answer_pdf_sha1": "07df2aebbe74", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02919', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '社會福利機構在做年度的方案評估，特別是運用量化測量工具來做評估時，其最主要的是要評估方案的 什麼項目是否達成或達成的程度？', '["願景（vision）", "方案的抽象目的（goals）", "方案的具體目標（objectives）", "理論假設"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "f9469744500c", "answer_pdf_sha1": "07df2aebbe74", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02920', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '在方案評估時，我們經常評估工作人員的服務態度是否親切、有禮貌，這個評估指標可稱為保證性 （assurance）。請問保證性是屬於那一個績效面向的評估指標？', '["效率（efficiency）", "品質（quality）", "成效（effectiveness）", "成本效益（cost-benefit）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "f9469744500c", "answer_pdf_sha1": "07df2aebbe74", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
